frastructure is in a class of its own.	[-0.05663311,0.039629396,-0.029516954,-0.04513389,0.04120215,-0.005382581,0.015682256,0.10133905,0.015128605,-0.030230347,-0.03525903,0.08660557,0.053673107,-0.032623384,0.040731046,-0.009696396,0.05579186,0.00766741,-0.07481044,-0.074301116,-0.009015112,-0.09142625,-0.011705459,-0.031243661,-0.042443957,0.0024520175,0.059678175,-0.013969362,-0.043870393,-0.021836497,-0.028084798,0.009054313,0.024645034,0.04781197,-0.07937103,0.0013251206,0.066531055,-0.02866385,0.027643787,-0.06025235,-0.045799702,-0.056625534,-0.07231332,0.03304704,-0.038943015,-0.01144046,0.032046147,-0.00786366,0.0015718016,-0.02751671,0.009641282,0.040120296,0.049670856,0.081793584,-0.106238015,-0.03220142,-0.026388444,-0.030111404,0.00087883923,-0.0065147798,0.04680697,0.027991638,0.008046433,0.1112756,-0.014457321,0.028942198,0.096467674,0.039632004,0.00163603,0.058742423,0.026066797,-0.045718078,0.0034097412,0.050372377,-0.049902797,-0.008067485,-0.0047457158,-0.119237624,0.028255079,0.04269831,0.078658395,0.024231084,0.008272083,-0.017512554,-0.026259158,0.052095916,-0.023353107,0.004338502,0.01919242,-0.05546322,0.07392563,0.05793602,0.00026572382,0.029767912,0.056826666,0.016360657,-0.012337948,-0.048256002,-0.06609752,0.010046362,-0.010117131,0.00678794,0.029227473,0.008715731,0.030242303,-0.011122488,0.00889194,-0.046202373,-0.062402423,0.044685572,-0.049151506,0.039739694,0.00014467051,0.02828328,0.015002924,0.011571364,-0.08830325,0.05137732,-0.004584519,0.03434608,0.070227586,0.0891434,-0.012823764,-0.055866674,-0.0063617923,0.028895833,-0.02813087,8.401857e-33,0.009166133,0.043886986,-0.05731982,-0.09688553,-0.024805179,-0.03188524,0.0005883547,0.057561584,-0.07804088,0.08244887,-0.08198285,-0.06253993,0.038977005,-0.0639357,0.08631607,-0.002735561,0.038368884,0.0034681347,0.11524596,0.006747708,0.035441186,-0.038475815,0.027646752,-0.001709704,0.05045933,-0.041994087,0.021076519,-0.023408761,0.041773867,0.008399518,-0.06135677,-0.0033711835,-0